/*
 * main.c - 内核初始化与比赛测试点 runner
 *
 * 这份内核的 main() 同时承担两类职责：
 *   1) 多核（多 hart）下的“一次性全局初始化”与“每 hart 初始化”。
 *   2) 创建一个特殊的用户态测试 runner 进程：
 *      - 从 EXT4 评测磁盘扫描 basic 测试点
 *      - 初赛当前只关注 RISC-V basic 组，输出评测器需要的结果段
 *      - 运行结束后主动关机
 *
 * 并发约束：
 *   - OpenSBI 可能从任意 hart 进入内核；通过原子变量 first/started
 *     保证只有一个 hart 执行全局初始化。
 */

// 非 0 表示全局初始化完成；其它 hart 自旋等待。
volatile static int started = 0;

// 最大测试点数量
#define MAX_TESTCASES 64

// 存储测试点信息
static ext4_file_t testcases[MAX_TESTCASES];
static int testcase_count = 0;

static void print_basic_case(const char* name, const char* body)
{
    printf("========== START %s ==========\n", name);
    printf("%s", body);
    printf("========== END %s ==========\n", name);
}

// 这个头文件通常认为其他.h文件都应该include
#ifndef __COMMON_H__
#define __COMMON_H__

// 类型定义

typedef char                   int8;
typedef short                  int16;
typedef int                    int32;
typedef long long              int64;
typedef unsigned char          uint8; 
typedef unsigned short         uint16;
typedef unsigned int           uint32;
typedef unsigned long long     uint64;

typedef unsigned long long         reg; 
typedef enum {false = 0, true = 1} bool;

#ifndef NULL
#define NULL ((void*)0)
#endif

#define NCPU 2

// 页面大小 4KB
#define PGSIZE 4096

// 内核保留的物理页数量（防止用户程序耗尽内存）
#define KERNEL_PAGES 1024

/* memory leyout */
#ifndef __MEMLAYOUT_H__
#define __MEMLAYOUT_H__

// 内核基地址 (使用OpenSBI时从0x80200000开始)
#define KERNEL_BASE 0x80200000ul

// UART 相关
#define UART_BASE  0x10000000ul
#define UART_IRQ   10

// platform-level interrupt controller(PLIC)
#define PLIC_BASE 0x0c000000ul
// PLIC寄存器区域的起始基地址，PILC是处理外部中断等的枢纽
#define PLIC_PRIORITY(id) (PLIC_BASE + (id) * 4)
#define PLIC_PENDING (PLIC_BASE + 0x1000)
#define PLIC_MENABLE(hart) (PLIC_BASE + 0x2000 + (hart)*0x100)
#define PLIC_SENABLE(hart) (PLIC_BASE + 0x2080 + (hart)*0x100)
#define PLIC_MPRIORITY(hart) (PLIC_BASE + 0x200000 + (hart)*0x2000)
#define PLIC_SPRIORITY(hart) (PLIC_BASE + 0x201000 + (hart)*0x2000)
#define PLIC_MCLAIM(hart) (PLIC_BASE + 0x200004 + (hart)*0x2000)
#define PLIC_SCLAIM(hart) (PLIC_BASE + 0x201004 + (hart)*0x2000)

// core local interruptor(CLINT)
// CLINT处理本地中断，主要是定时器中断
#define CLINT_BASE 0x2000000ul
#define CLINT_MSIP(hartid) (CLINT_BASE + 4 * (hartid))
#define CLINT_MTIMECMP(hartid) (CLINT_BASE + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT_BASE + 0xBFF8)

// 物理内存结束地址 (128MB, 从0x80000000开始到0x88000000)
#define PHYSTOP (0x80000000ul + 128*1024*1024)

// 用户态虚拟地址空间布局
// 最大虚拟地址 (SV39: 2^38)
#define VA_MAX (1ul << 38)

// 跳板页：映射在虚拟地址空间最高处
// 内核和用户态共享同一虚拟地址
#define TRAMPOLINE (VA_MAX - PGSIZE)

// trapframe页：紧邻跳板页下方
#define TRAPFRAME (TRAMPOLINE - PGSIZE)

// 内核栈：每个CPU一个，从 TRAMPOLINE 往下分配
// 每个栈由一个guard页和一个栈页组成
#define KSTACK(cpu) (TRAMPOLINE - ((cpu) + 1) * 2 * PGSIZE)

//virtio相关
#define VIRTIO_BASE 0x10001000ul

#include "common.h"

// 获取当前CPU的hartid
static inline uint64 r_mhartid()
{
  uint64 x;
  asm volatile("csrr %0, mhartid" : "=r" (x) );
  return x;
}

// Machine Status Register, mstatus
#define MSTATUS_MPP_MASK (3L << 11) // previous mode.
#define MSTATUS_MPP_M (3L << 11)
#define MSTATUS_MPP_S (1L << 11)
#define MSTATUS_MPP_U (0L << 11)
#define MSTATUS_MIE (1L << 3)    // machine-mode interrupt enable.

static inline uint64 r_mstatus()
{
  uint64 x;
  asm volatile("csrr %0, mstatus" : "=r" (x) );
  return x;
}

static inline void  w_mstatus(uint64 x)
{
  asm volatile("csrw mstatus, %0" : : "r" (x));
}

// machine exception program counter, holds the
// instruction address to which a return from
// exception will go.
static inline void w_mepc(uint64 x)
{
  asm volatile("csrw mepc, %0" : : "r" (x));
}

// Supervisor Status Register, sstatus

#define SSTATUS_SPP (1L << 8)  // Previous mode, 1=Supervisor, 0=User
#define SSTATUS_SPIE (1L << 5) // Supervisor Previous Interrupt Enable
#define SSTATUS_UPIE (1L << 4) // User Previous Interrupt Enable
#define SSTATUS_SIE (1L << 1)  // Supervisor Interrupt Enable
#define SSTATUS_UIE (1L << 0)  // User Interrupt Enable

static inline uint64 r_sstatus()
{
  uint64 x;
  asm volatile("csrr %0, sstatus" : "=r" (x) );
  return x;

typedef unsigned char uint8_t;

#define UART_BASE 0x1fe001e0UL
#define UART_THR 0
#define UART_LSR 5
#define UART_LSR_THRE 0x20
#define ACPI_GED_SLEEP_CTL 0x100e001cUL
#define ACPI_GED_SLEEP_S5 0x34

static void putc(char ch)
{
    volatile uint8_t *uart = (volatile uint8_t *)UART_BASE;
    while ((uart[UART_LSR] & UART_LSR_THRE) == 0) {
    }
    uart[UART_THR] = (uint8_t)ch;
}

static void puts(const char *s)
{
    while (*s) {
        if (*s == '\n') {
            putc('\r');
        }
        putc(*s++);
    }
}

