#include "riscv.h"
#include "memlayout.h"
#include "dev/timer.h"

/*
 * start.c - S-mode 早期初始化入口
 *
 * 执行上下文：OpenSBI 已将 CPU 切换到 S-mode，并跳转到 _entry（见 entry.S）。
 * 本文件的 start() 主要做“最小化且安全”的早期设置，然后直接进入 main()。
 *
 * 说明：
 *   - 这里实现了一套 early_putc/early_puts，用于在更完整的 uart/print 初始化前
 *     输出调试信息（直接轮询 UART 寄存器）。
 *   - 若后续 main() 会重新初始化 UART/PLIC/分页等，这里的设置应尽量保守。
 */

void main(void);

// 每 CPU 4KB 内核栈；entry.S 会按 hartid 为 sp 选择对应栈顶。
__attribute__ ((aligned (16))) uint8 CPU_stack[4096 * NCPU];

// 早期 UART 输出：直接轮询 UART 寄存器，不依赖驱动初始化。
static void early_putc(char c)
{
    volatile char* uart = (volatile char*)UART_BASE;
    while ((uart[5] & 0x20) == 0);  // 等待发送缓冲区空
    uart[0] = c;
}

// 输出以 \0 结尾的字符串。
static void early_puts(const char* s)
{
    while (*s) {
        early_putc(*s++);
    }
}

// S-mode 下运行（由 OpenSBI 跳入），完成最小配置后跳转到 main()。
void start(void)
{

OUTPUT_ARCH(loongarch)
ENTRY(_start)

SECTIONS
{
  . = 0x90000000;

  .text : {
    *(.text.entry)
    *(.text .text.*)
  }

  .rodata : {
    *(.rodata .rodata.*)
  }

  .data : {
    *(.data .data.*)
  }

  .bss : {
    __bss_start = .;
    *(.bss .bss.*)
    *(COMMON)
    __bss_end = .;
  }

  . = ALIGN(16);
  __stack_bottom = .;
  . += 0x4000;
  __stack_top = .;
}
